const STORAGE_KEY = "notepad-content";

let _hasUnsavedChanges = false;

function onBeforeUnload(e) {
    if (_hasUnsavedChanges) {
        e.preventDefault();
    }
}

window.addEventListener("beforeunload", onBeforeUnload);

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
    _hasUnsavedChanges = false;
}

export function load() {
    return localStorage.getItem(STORAGE_KEY) ?? "";
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
    _hasUnsavedChanges = false;
}

export function setHasUnsavedChanges(value) {
    _hasUnsavedChanges = value;
}

export function dispose() {
    window.removeEventListener("beforeunload", onBeforeUnload);
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput"
              @bind:after="OnContentChanged" placeholder="Type your notes here..."></textarea>
</div>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = "";
    private string lastSavedContent = "";
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", Assets["Components/Pages/Notepad.razor.js"]);

            content = await module.InvokeAsync<string>("load");
            lastSavedContent = content;

            autoSaveTimer = new Timer(async _ =>
            {
                await InvokeAsync(AutoSave);
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));

            StateHasChanged();
        }
    }

    private async Task OnContentChanged()
    {
        if (module is not null && content != lastSavedContent)
        {
            await module.InvokeVoidAsync("setHasUnsavedChanges", true);
        }
    }

    private async Task AutoSave()
    {
        if (content != lastSavedContent)
        {
            await SaveContent();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await SaveContent();
    }

    private async Task SaveContent()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("save", content);
            lastSavedContent = content;
            lastSavedAt = DateTime.Now;
        }
    }

    private async Task Clear()
    {
        if (module is not null)
        {
            content = "";
            lastSavedContent = "";
            lastSavedAt = null;
            await module.InvokeVoidAsync("clear");
        }
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Dispose();
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose");
            await module.DisposeAsync();
        }
    }
}

